/** Maps Prisma scalar type names to their TypeScript equivalents. */
const SCALAR_MAP: Record<string, string> = {
  String: 'string',
  Int: 'number',
  Float: 'number',
  Decimal: 'number',
  BigInt: 'bigint',
  Boolean: 'boolean',
  DateTime: 'Date',
  Json: 'unknown',
  Bytes: 'Uint8Array',
}

/**
 * Returns the TypeScript type string for a DMMF field, accounting for
 * nullability and list modifiers. Returns `null` for relation (`object`) and
 * `unsupported` fields, which are intentionally excluded from the generated
 * interfaces.
 */
export function mapFieldToTsType(field: DMMF.Field, enumNames: ReadonlySet<string>): string | null {
  let base: string

  if (field.kind === 'scalar') {
    base = SCALAR_MAP[field.type] ?? 'unknown'
  } else if (field.kind === 'enum' && enumNames.has(field.type)) {
    base = field.type
  } else {
    return null
  }

  if (field.isList) base = `${base}[]`
  if (!field.isRequired) base = `${base} | null`

  return base
}

