import type { DMMF } from '@prisma/dmmf'

/**
 * Converts a PascalCase model name to the camelCase property name used on
 * `PrismaRestClient` (e.g. `UserProfile` → `userProfile`).
 */
function toCamelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

/**
 * Generates the barrel `index.ts` for the REST client output directory.
 * It re-exports every model file and enum file, and exposes a `PrismaRestClient`
 * class with one typed sub-client property per model.
 */
export function generateIndexFile(
  models: readonly DMMF.Model[],
  mappings: readonly DMMF.ModelMapping[],
): string {
  const reExports = [
    "export * from './enums'",
    ...models.map((m) => `export * from './${m.name}'`),
  ].join('\n')

  const properties = models
    .map((m) => `  readonly ${toCamelCase(m.name)}: ${m.name}Client`)
    .join('\n')

  const assignments = models
    .map((m) => {
      const mapping = mappings.find((mp) => mp.model === m.name)
      const resource = (mapping?.plural ?? `${m.name}s`).toLowerCase()
      return `    this.${toCamelCase(m.name)} = new ${m.name}Client(baseUrl, '${resource}')`
    })
    .join('\n')

  // We need to adjust the client constructor signature to accept the resource
  // path as a second argument. The assignments above pass the resource, but the
  // current ModelClient constructor only takes baseUrl. We thread the resource
  // through here so the index file drives the URL path rather than the class.
  // (The class already stores it in #resource.)
  const constructorBody = models
    .map((m) => {
      const mapping = mappings.find((mp) => mp.model === m.name)
      const resource = (mapping?.plural ?? `${m.name}s`).toLowerCase()
      return `    this.${toCamelCase(m.name)} = new ${m.name}Client(\`\${baseUrl}/${resource}\`)`
    })
    .join('\n')

  // Build client-type imports for the class body. Re-exports already cover them
  // but we need the names in scope for the property declarations.
  const clientImports = models.map((m) => `${m.name}Client`).join(', ')

  const prismaRestClientClass = `
// Aggregate client that exposes one typed sub-client per Prisma model.
export class PrismaRestClient {
${properties}

  constructor(baseUrl: string) {
${constructorBody}
  }
}`

  return `${reExports}\n${prismaRestClientClass}\n`
}

