import type { DMMF } from '@prisma/dmmf'

import { mapFieldToTsType } from './type-mapping'

/** Returns true for fields that carry their own value rather than delegating to a relation. */
function isDataField(field: DMMF.Field): boolean {
  return field.kind === 'scalar' || field.kind === 'enum'
}

/**
 * Returns true for scalar/enum fields that are writable by the caller on create,
 * i.e. fields that are not auto-generated or managed automatically by the database.
 */
function isWritableOnCreate(field: DMMF.Field): boolean {
  if (!isDataField(field)) return false
  if (field.isReadOnly) return false
  if (field.isUpdatedAt) return false
  // Skip IDs that have a server-side default (autoincrement, uuid, cuid, etc.)
  if (field.isId && field.hasDefaultValue) return false
  return true
}

/** Returns true for scalar/enum fields that are writable by the caller on update. */
function isWritableOnUpdate(field: DMMF.Field): boolean {
  if (!isDataField(field)) return false
  if (field.isReadOnly) return false
  if (field.isUpdatedAt) return false
  // ID fields are used for lookup, not for updating
  if (field.isId) return false
  return true
}

/** Builds a comma-separated `key: Type` interface body, indented by two spaces. */
function buildInterfaceBody(
  entries: Array<{ name: string; tsType: string; required: boolean }>,
): string {
  return entries.map(({ name, tsType, required }) => `  ${name}${required ? '' : '?'}: ${tsType}`).join('\n')
}

/**
 * Generates the complete TypeScript source for one model file, including the
 * model interface, input types, and a REST API client class.
 */
export function generateModelFile(
  model: DMMF.Model,
  enumNames: ReadonlySet<string>,
  resourcePath: string,
): string {
  const modelName = model.name

  // Collect all enum types referenced by this model's fields so we can import them.
  const referencedEnums = new Set<string>()
  for (const field of model.fields) {
    if (field.kind === 'enum' && enumNames.has(field.type)) {
      referencedEnums.add(field.type)
    }
  }

  const enumImport =
    referencedEnums.size > 0
      ? `import type { ${[...referencedEnums].sort().join(', ')} } from './enums'\n\n`
      : ''

  // --- Model interface ---
  const modelFields: Array<{ name: string; tsType: string; required: boolean }> = []
  for (const field of model.fields) {
    const tsType = mapFieldToTsType(field, enumNames)
    if (tsType !== null) {
      modelFields.push({ name: field.name, tsType, required: true })
    }
  }

  const modelInterface = `export interface ${modelName} {\n${buildInterfaceBody(modelFields)}\n}`

  // --- CreateInput ---
  const createFields: Array<{ name: string; tsType: string; required: boolean }> = []
  for (const field of model.fields) {
    if (!isWritableOnCreate(field)) continue
    const tsType = mapFieldToTsType(field, enumNames)
    if (tsType === null) continue
    // A field is required in CreateInput only if it is required by the schema and
    // carries no default value (otherwise the caller may omit it).
    const required = field.isRequired && !field.hasDefaultValue
    createFields.push({ name: field.name, tsType, required })
  }

  const createInputInterface = `export interface Create${modelName}Input {\n${buildInterfaceBody(createFields)}\n}`

  // --- UpdateInput ---
  const updateFields: Array<{ name: string; tsType: string; required: boolean }> = []
  for (const field of model.fields) {
    if (!isWritableOnUpdate(field)) continue
    const tsType = mapFieldToTsType(field, enumNames)
    if (tsType === null) continue
    updateFields.push({ name: field.name, tsType, required: false })
  }

  const updateInputInterface = `export interface Update${modelName}Input {\n${buildInterfaceBody(updateFields)}\n}`

  // --- WhereUniqueInput ---
  const uniqueFields: Array<{ name: string; tsType: string; required: boolean }> = []
  for (const field of model.fields) {
    if (!isDataField(field)) continue
    if (!field.isId && !field.isUnique) continue
    const tsType = mapFieldToTsType(field, enumNames)
    if (tsType === null) continue
    // Strip nullability from unique field types – you always need to provide a real value.
    const nonNullableType = tsType.replace(' | null', '')
    uniqueFields.push({ name: field.name, tsType: nonNullableType, required: false })
  }

  const whereUniqueInputInterface = `export interface ${modelName}WhereUniqueInput {\n${buildInterfaceBody(uniqueFields)}\n}`

  // --- Client class ---
  const clientClass = buildClientClass(modelName, resourcePath)

  return [enumImport + modelInterface, createInputInterface, updateInputInterface, whereUniqueInputInterface, clientClass].join(
    '\n\n',
  )
}

function buildClientClass(modelName: string, resourcePath: string): string {
  return `export class ${modelName}Client {
  readonly #baseUrl: string
  readonly #resource: string

  constructor(baseUrl: string) {
    this.#baseUrl = baseUrl
    this.#resource = '${resourcePath}'
  }

  async #request(method: string, url: string, body?: unknown): Promise<unknown> {
    const response = await fetch(url, {
      method,
      headers: body !== undefined ? { 'Content-Type': 'application/json' } : {},
      body: body !== undefined ? JSON.stringify(body) : undefined,
    })
    if (!response.ok) {
      throw new Error(\`HTTP \${response.status}: \${response.statusText}\`)
    }
    if (response.status === 204) return null
    return response.json() as Promise<unknown>
  }

  async findMany(args?: {
    where?: Partial<${modelName}>
    skip?: number
    take?: number
  }): Promise<${modelName}[]> {
    const params = new URLSearchParams()
    if (args?.skip !== undefined) params.set('skip', String(args.skip))
    if (args?.take !== undefined) params.set('take', String(args.take))
    if (args?.where !== undefined) params.set('where', JSON.stringify(args.where))
    const query = params.size > 0 ? \`?\${params}\` : ''
    return this.#request('GET', \`\${this.#baseUrl}/\${this.#resource}\${query}\`) as Promise<${modelName}[]>
  }

  async findUnique(args: { where: ${modelName}WhereUniqueInput }): Promise<${modelName} | null> {
    const id = Object.values(args.where).find((v) => v !== undefined)
    return this.#request('GET', \`\${this.#baseUrl}/\${this.#resource}/\${id}\`) as Promise<${modelName} | null>
  }

  async create(data: Create${modelName}Input): Promise<${modelName}> {
    return this.#request('POST', \`\${this.#baseUrl}/\${this.#resource}\`, data) as Promise<${modelName}>
  }

  async update(args: { where: ${modelName}WhereUniqueInput; data: Update${modelName}Input }): Promise<${modelName}> {
    const id = Object.values(args.where).find((v) => v !== undefined)
    return this.#request('PATCH', \`\${this.#baseUrl}/\${this.#resource}/\${id}\`, args.data) as Promise<${modelName}>
  }

  async delete(args: { where: ${modelName}WhereUniqueInput }): Promise<${modelName}> {
    const id = Object.values(args.where).find((v) => v !== undefined)
    return this.#request('DELETE', \`\${this.#baseUrl}/\${this.#resource}/\${id}\`) as Promise<${modelName}>
  }
}`
}

import type { DMMF } from '@prisma/dmmf'

/**
 * Converts a PascalCase model name to the camelCase property name used on
 * `PrismaRestClient` (e.g. `UserProfile` → `userProfile`).
 */
function toCamelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

/**
 * Generates the barrel `index.ts` for the REST client output directory.
 * It re-exports every model file and the enums file, and exposes a
 * `PrismaRestClient` class with one typed sub-client property per model.
 * Each sub-client constructor already has its resource path baked in from
 * generation time, so only the base URL is required here.
 */
export function generateIndexFile(
  models: readonly DMMF.Model[],
): string {
  const reExports = [
    "export * from './enums'",
    ...models.map((m) => `export * from './${m.name}'`),
  ].join('\n')

  const properties = models
    .map((m) => `  readonly ${toCamelCase(m.name)}: ${m.name}Client`)
    .join('\n')

  const constructorAssignments = models
    .map((m) => `    this.${toCamelCase(m.name)} = new ${m.name}Client(baseUrl)`)
    .join('\n')

  const prismaRestClientClass = `
// Aggregate client that exposes one typed sub-client per Prisma model.
export class PrismaRestClient {
${properties}

  constructor(baseUrl: string) {
${constructorAssignments}
  }
}`

  return `${reExports}\n${prismaRestClientClass}\n`
}

