  it('returns the correct manifest', async () => {
    const generator = new RestClientGenerator()
    const manifest = await generator.getManifest({
      name: 'restClient',
      provider: { fromEnvVar: null, value: 'prisma-rest-client' },
      output: null,
      config: {},
      binaryTargets: [],
      previewFeatures: [],
      sourceFilePath: '/fake/schema.prisma',
    })

    expect(manifest.prettyName).toBe('Prisma REST API Client')
    expect(manifest.defaultOutput).toBe('generated/rest-client')
  })

  it('throws when output is missing', async () => {
    const generator = new RestClientGenerator()
    const options = makeOptions(outputDir)
    options.generator.output = null

    await expect(generator.generate(options)).rejects.toThrow('prisma-rest-client')
  })

  describe('generated User.ts', () => {
    let userTs: string

    beforeEach(async () => {
      await new RestClientGenerator().generate(makeOptions(outputDir))
      userTs = await fs.readFile(path.join(outputDir, 'User.ts'), 'utf-8')
    })

    it('exports the model interface', () => {
      expect(userTs).toContain('export interface User {')
      expect(userTs).toContain('id: number')
      expect(userTs).toContain('email: string')
      expect(userTs).toContain('name: string | null')
      expect(userTs).toContain('role: Role')
    })

    it('imports enum types used by the model', () => {
      expect(userTs).toContain("import type { Role } from './enums'")
    })

    it('exports CreateUserInput with correct required/optional fields', () => {
      expect(userTs).toContain('export interface CreateUserInput {')
      // email is required (isRequired=true, hasDefaultValue=false)
      expect(userTs).toContain('email: string')
      // name is optional (isRequired=false)
      expect(userTs).toContain('name?: string | null')
      // role has a default value so it is optional in CreateInput
      expect(userTs).toContain('role?: Role')
      // id is excluded (auto-generated)
      expect(userTs.slice(userTs.indexOf('CreateUserInput'))).not.toMatch(/\bid: /)
    })

    it('exports UpdateUserInput with all fields optional', () => {
      expect(userTs).toContain('export interface UpdateUserInput {')
      expect(userTs).toContain('email?: string')
      expect(userTs).toContain('name?: string | null')
      expect(userTs).toContain('role?: Role')
    })

    it('exports UserWhereUniqueInput with id and unique fields', () => {
      expect(userTs).toContain('export interface UserWhereUniqueInput {')
      expect(userTs).toContain('id?: number')
      expect(userTs).toContain('email?: string')
    })

    it('exports a UserClient class with all CRUD methods', () => {
      expect(userTs).toContain('export class UserClient {')
      expect(userTs).toContain('async findMany(')
      expect(userTs).toContain('async findUnique(')
      expect(userTs).toContain('async create(')
      expect(userTs).toContain('async update(')
      expect(userTs).toContain('async delete(')
    })

    it('uses the correct resource path in the client', () => {
      expect(userTs).toContain("this.#resource = 'users'")
    })
  })

  describe('generated enums.ts', () => {
    it('exports the Role enum', async () => {
      await new RestClientGenerator().generate(makeOptions(outputDir))
      const enumsTs = await fs.readFile(path.join(outputDir, 'enums.ts'), 'utf-8')

      expect(enumsTs).toContain('export enum Role {')
      expect(enumsTs).toContain("USER = 'USER'")
      expect(enumsTs).toContain("ADMIN = 'ADMIN'")
    })
  })

  describe('generated index.ts', () => {
    let indexTs: string

    beforeEach(async () => {
      await new RestClientGenerator().generate(makeOptions(outputDir))
      indexTs = await fs.readFile(path.join(outputDir, 'index.ts'), 'utf-8')
    })

    it('re-exports enums and model files', () => {
      expect(indexTs).toContain("export * from './enums'")
      expect(indexTs).toContain("export * from './User'")
    })

    it('exports PrismaRestClient with typed sub-client properties', () => {
      expect(indexTs).toContain('export class PrismaRestClient {')
      expect(indexTs).toContain('readonly user: UserClient')
    })

    it('instantiates each sub-client in the constructor', () => {
      expect(indexTs).toContain('new UserClient(baseUrl)')
    })
  })

  it('generates an empty enums.ts when there are no enums', async () => {
    const options = makeOptions(outputDir)
    // Remove enums from the fixture
    ;(options.dmmf as any).datamodel = {
      ...minimalDmmf.datamodel,
      enums: [],
    }

    await new RestClientGenerator().generate(options)

    const enumsTs = await fs.readFile(path.join(outputDir, 'enums.ts'), 'utf-8')
    expect(enumsTs).toBe('')
  })
})

